import React, { InputHTMLAttributes, ReactNode } from "react";

import { useStableId } from "../hooks/useStableId.js";
import styles from "./CyberpunkInput.module.css";

export interface CyberpunkInputProps
  extends Omit<InputHTMLAttributes<HTMLInputElement>, "helperText"> {
  label?: string;
  variant?: "default" | "long" | "full";
  helperText?: string;
  icon?: ReactNode;
}

export function CyberpunkInput({
  label,
  variant = "default",
  className = "",
  id,
  disabled,
  readOnly,
  helperText,
  icon,
  ...props
}: CyberpunkInputProps) {
  const inputId = useStableId("input", id);
  const isDisabledOrReadOnly = disabled || readOnly;

  return (
    <div className={`${styles.cyberInput} ${styles[variant]} ${className}`.trim()}>
      {label ? (
        <label htmlFor={inputId} className={styles.label}>
          {label}
        </label>
      ) : null}
      <div
        className={`${styles.inputContainer} ${isDisabledOrReadOnly ? styles.disabledContainer : ""} ${icon ? styles.withIcon : ""}`.trim()}
      >
        {icon ? <div className={styles.icon}>{icon}</div> : null}
        <input id={inputId} className={styles.input} disabled={disabled} readOnly={readOnly} {...props} />
      </div>
      {helperText ? <div className={styles.helperText}>{helperText}</div> : null}
    </div>
  );
}

.cyberInput {
  --input-width: 240px;
  --input-font-size: 1rem;
  --input-padding-top: 12px;
  --input-padding-right: 12px;
  --input-padding-bot: 12px;
  --input-padding-left: 12px;
  --focus-border-color: var(--color-accent-primary, var(--text-primary));
  --label-offset-top: -2px;
  --label-offset-left: 12px;
  --label-padding: 1px 8px;
  --label-font-size: 0.85rem;

  position: relative;
  margin-top: 10px;
  margin-bottom: 1rem;
  font-size: var(--input-font-size);
}

.inputContainer {
  position: relative;
  width: var(--input-width);
  border: 1px solid var(--color-border-default);
  background: var(--color-bg-tile);
  margin-top: 6px;
}

.input {
  width: 100%;
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-size: inherit;
  background: transparent;
  padding: var(--input-padding-top) var(--input-padding-right) var(--input-padding-bot) var(--input-padding-left);
  border: none;
  outline: none;
  box-sizing: border-box;
}

.cyberInput:focus-within .label {
  color: var(--focus-border-color);
}

.cyberInput:focus-within .inputContainer {
  border-color: var(--focus-border-color);
}

.label {
  position: absolute;
  top: var(--label-offset-top);
  left: var(--label-offset-left);
  background: var(--color-bg-tile);
  padding: var(--label-padding);
  font-family: var(--font-mono);
  font-size: var(--label-font-size);
  font-weight: 500;
  color: var(--text-secondary);
  z-index: 1;
  line-height: 1.2;
  transition: background-color var(--transition-normal), color var(--transition-normal);
}

.inputContainer:hover {
  border-color: var(--color-border-hover);
}

.cyberInput:focus-within .inputContainer:hover {
  border-color: var(--focus-border-color);
}

.long {
  --input-width: 360px;
}

.full {
  --input-width: 100%;
  width: 100%;
  display: block;
}

.input:disabled,
.input[readonly] {
  opacity: 0.7;
  cursor: not-allowed;
}

.disabledContainer {
  background: var(--color-bg-secondary) !important;
  cursor: not-allowed;
}

.helperText {
  margin-top: 0.5rem;
  font-size: 0.75rem;
  color: var(--text-secondary);
  font-family: var(--font-mono);
}

.icon {
  position: absolute;
  right: 12px;
  top: 50%;
  transform: translateY(-50%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
  pointer-events: none;
  z-index: 1;
}

.withIcon .input {
  padding-right: 44px;
}

import { useId } from "react";

export function useStableId(prefix: string, explicitId?: string): string {
  const reactId = useId().replace(/:/g, "");
  return explicitId || `${prefix}-${reactId}`;
}
